%% run_greenhouse.m
clc; clear; close all;
init_greenhouse;  % Load parameters and initial conditions %[output:05199120]

% Initialize PID integral errors
intT = 0; intH = 0; intC = 0;
uW = 0;                 % irrigation starts OFF
uT = 0; uH = 0; uC = 0; % (optional) initialize other actuators for logging


for k = 1:length(time)-1
    
    % --- Compute control errors ---
    eT = Tsp - T;
    eH = Hsp - H;
    eC = Csp - C;
    
    % --- PID control (simplified to proportional + integral) ---
    intT = intT + eT*dt;
    intH = intH + eH*dt;
    intC = intC + eC*dt;
    
    uT = Kp_T*eT + Ki_T*intT;
    uH = Kp_H*eH + Ki_H*intH;
    uC = Kp_C*eC + Ki_C*intC;
    
    % --- Relay control for irrigation ---
    if W < Wmin
        uW = 1; % irrigation ON
    elseif W > Wmax
        uW = 0; % irrigation OFF
    else
        % between Wmin and Wmax -> keep previous uW
    uW = uW;
    end
    
    % --- Update greenhouse states ---
    [T, H, W, C, B] = greenhouse_step(T,H,W,C,B, ...
        uT,uH,uW,uC,dt,aT,bT,dT,aH,bH,cH,aW,bW,aC,bC,aB,alphaT,alphaH,alphaC,alphaL);
    
    % --- Log results ---
    T_log(end+1) = T;
    H_log(end+1) = H;
    W_log(end+1) = W;
    C_log(end+1) = C;
    B_log(end+1) = B;
end

% ---- Plot results ----
figure; %[output:59afb3d5]
subplot(3,2,1); plot(time,T_log,'r'); ylabel('Temperature (°C)'); grid on; %[output:59afb3d5]
subplot(3,2,2); plot(time,H_log,'b'); ylabel('Humidity (%)'); grid on; %[output:59afb3d5]
subplot(3,2,3); plot(time,W_log,'g'); ylabel('Soil Moisture'); grid on; %[output:59afb3d5]
subplot(3,2,4); plot(time,C_log,'m'); ylabel('CO2 (ppm)'); grid on; %[output:59afb3d5]
subplot(3,2,5); plot(time,B_log,'k'); ylabel('Biomass (kg)'); grid on; %[output:59afb3d5]
xlabel('Time (hours)'); sgtitle('Sustainable Greenhouse Simulation'); %[output:59afb3d5]

% ---- Sustainability metrics ----
recycledWater = sum(W_log < Wmin);       % irrigation hours
totalHours = length(time);
waterSavings = recycledWater / totalHours;

biomassYield = B_log(end) - B_log(1);
energyUsed = sum(abs(uT) + abs(uH) + abs(uC)) * dt;
energyEfficiency = biomassYield / energyUsed;

fprintf('\n🌱 Water savings = %.2f%%\n', 100*waterSavings); %[output:638bfba0]
fprintf('⚡ Energy efficiency = %.4f kg/kWh\n', energyEfficiency); %[output:5c61edeb]
fprintf('🍅 Final biomass = %.2f kg\n', B); %[output:1a45bba1]
fprintf('\n--- Sustainability metrics ---\n'); %[output:707b4cd3]
fprintf('Water savings: %.2f %%\n', 100*waterSavings); %[output:7a4142a7]
fprintf('Energy efficiency: %.4f kg/kWh\n', energyEfficiency); %[output:01337753]
fprintf('Final biomass: %.2f kg\n', B_log(end)); %[output:5d4f7b15]

% save results for your report
if ~isfolder('results'), mkdir results; end
saveas(gcf,'results/greenhouse_plots.png'); %[output:59afb3d5]
TBL = table((0:numel(T_log)-1).', T_log.', H_log.', W_log.', C_log.', B_log.', ...
    'VariableNames',{'Hour','Temp','Hum','Moist','CO2','Biomass'});
writetable(TBL,'results/greenhouse_timeseries.csv');



